import { useState, useRef, useCallback } from 'react'
import { Upload, X, Image, Video, Music, FileText, Loader2, Link as LinkIcon } from 'lucide-react'
import { validateFile, FileType } from '@/utils/upload'

interface FileUploadProps {
  type: FileType
  value: string
  onChange: (url: string) => void
  label?: string
  placeholder?: string
  accept?: string
  maxSize?: number
  disabled?: boolean
}

// Tailwind classes for URL input
const URL_INPUT_CLASSES = 'w-full pl-10 pr-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all'

// Tailwind classes for toggle buttons
const BUTTON_BASE_CLASSES = 'flex-1 flex items-center justify-center gap-2 px-3 py-2 rounded-md text-sm font-medium transition-colors'
const BUTTON_ACTIVE_CLASSES = 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm'
const BUTTON_INACTIVE_CLASSES = 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'

const typeConfig = {
  image: {
    icon: Image,
    accept: 'image/jpeg,image/png,image/gif,image/webp',
    label: 'imagen',
    preview: true,
  },
  video: {
    icon: Video,
    accept: 'video/mp4,video/webm,video/quicktime',
    label: 'video',
    preview: true,
  },
  audio: {
    icon: Music,
    accept: 'audio/mpeg,audio/ogg,audio/wav,audio/mp3',
    label: 'audio',
    preview: false,
  },
  file: {
    icon: FileText,
    accept: 'application/pdf,.doc,.docx,.txt',
    label: 'archivo',
    preview: false,
  },
}

export const FileUpload = ({
  type,
  value,
  onChange,
  label,
  placeholder,
  disabled = false,
}: FileUploadProps) => {
  const [isDragging, setIsDragging] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [useUrl, setUseUrl] = useState(true)
  const [urlInput, setUrlInput] = useState(value)
  const fileInputRef = useRef<HTMLInputElement>(null)

  const config = typeConfig[type]
  const Icon = config.icon

  const handleFileSelect = useCallback(async (file: File) => {
    setError(null)
    setIsLoading(true)

    try {
      const validation = validateFile(file, type)
      if (!validation.valid) {
        setError(validation.error || 'Archivo no valido')
        return
      }

      // Convertir a base64 para preview
      const reader = new FileReader()
      reader.onloadend = () => {
        const result = reader.result as string
        onChange(result)
        setIsLoading(false)
      }
      reader.onerror = () => {
        setError('Error al leer el archivo')
        setIsLoading(false)
      }
      reader.readAsDataURL(file)
    } catch (_err) {
      setError('Error al procesar el archivo')
      setIsLoading(false)
    }
  }, [type, onChange])

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)

    const file = e.dataTransfer.files[0]
    if (file) {
      handleFileSelect(file)
    }
  }, [handleFileSelect])

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(true)
  }, [])

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)
  }, [])

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      handleFileSelect(file)
    }
  }

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const url = e.target.value
    setUrlInput(url)
    onChange(url)
  }

  const clearFile = () => {
    onChange('')
    setUrlInput('')
    setError(null)
    if (fileInputRef.current) {
      fileInputRef.current.value = ''
    }
  }

  return (
    <div className="space-y-3">
      {label && (
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          {label}
        </label>
      )}

      {/* Toggle between URL and Upload */}
      <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-lg">
        <button
          type="button"
          onClick={() => setUseUrl(true)}
          className={`${BUTTON_BASE_CLASSES} ${useUrl ? BUTTON_ACTIVE_CLASSES : BUTTON_INACTIVE_CLASSES}`}
        >
          <LinkIcon className="w-4 h-4" />
          URL
        </button>
        <button
          type="button"
          onClick={() => setUseUrl(false)}
          className={`${BUTTON_BASE_CLASSES} ${!useUrl ? BUTTON_ACTIVE_CLASSES : BUTTON_INACTIVE_CLASSES}`}
        >
          <Upload className="w-4 h-4" />
          Subir
        </button>
      </div>

      {useUrl ? (
        /* URL Input */
        <div className="relative">
          <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="url"
            value={urlInput}
            onChange={handleUrlChange}
            placeholder={placeholder || `https://example.com/${config.label}.${type === 'image' ? 'jpg' : type === 'video' ? 'mp4' : type === 'audio' ? 'mp3' : 'pdf'}`}
            disabled={disabled}
            className={URL_INPUT_CLASSES}
          />
        </div>
      ) : (
        /* File Upload */
        <div
          onDrop={handleDrop}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onClick={() => !disabled && fileInputRef.current?.click()}
          className={`
            relative border-2 border-dashed rounded-xl p-6 text-center cursor-pointer transition-all
            ${isDragging
              ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20'
              : 'border-gray-300 dark:border-gray-700 hover:border-primary-400 dark:hover:border-primary-600'
            }
            ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
          `}
        >
          <input
            ref={fileInputRef}
            type="file"
            accept={config.accept}
            onChange={handleInputChange}
            disabled={disabled}
            className="hidden"
          />

          {isLoading ? (
            <div className="flex flex-col items-center">
              <Loader2 className="w-10 h-10 text-primary-600 animate-spin mb-3" />
              <p className="text-sm text-gray-600 dark:text-gray-400">Procesando...</p>
            </div>
          ) : (
            <div className="flex flex-col items-center">
              <div className="w-12 h-12 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center justify-center mb-3">
                <Icon className="w-6 h-6 text-gray-400" />
              </div>
              <p className="text-sm font-medium text-gray-900 dark:text-white mb-1">
                Arrastra tu {config.label} aqui
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                o haz clic para seleccionar
              </p>
            </div>
          )}
        </div>
      )}

      {/* Error */}
      {error && (
        <p className="text-sm text-red-600 dark:text-red-400">{error}</p>
      )}

      {/* Preview */}
      {value && (
        <div className="relative rounded-xl overflow-hidden bg-gray-100 dark:bg-gray-800">
          {type === 'image' && (
            <img
              src={value}
              alt="Preview"
              className="w-full h-48 object-cover"
              onError={() => setError('No se pudo cargar la imagen')}
            />
          )}
          {type === 'video' && (
            <video
              src={value}
              controls
              className="w-full h-48 object-cover"
              onError={() => setError('No se pudo cargar el video')}
            />
          )}
          {type === 'audio' && (
            <div className="p-4 flex items-center gap-3">
              <div className="p-3 bg-primary-100 dark:bg-primary-900/30 rounded-lg">
                <Music className="w-6 h-6 text-primary-600 dark:text-primary-400" />
              </div>
              <audio src={value} controls className="flex-1" />
            </div>
          )}
          {type === 'file' && (
            <div className="p-4 flex items-center gap-3">
              <div className="p-3 bg-primary-100 dark:bg-primary-900/30 rounded-lg">
                <FileText className="w-6 h-6 text-primary-600 dark:text-primary-400" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-medium text-gray-900 dark:text-white truncate">
                  Archivo seleccionado
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400 truncate">
                  {value.substring(0, 50)}...
                </p>
              </div>
            </div>
          )}

          {/* Clear button */}
          <button
            type="button"
            onClick={(e) => {
              e.stopPropagation()
              clearFile()
            }}
            className="absolute top-2 right-2 p-1.5 bg-black/50 hover:bg-black/70 rounded-lg transition-colors"
          >
            <X className="w-4 h-4 text-white" />
          </button>
        </div>
      )}
    </div>
  )
}

import { Moon, Sun, Bell, Search, Menu } from 'lucide-react'
import { useTheme } from '@/contexts'
import { useState } from 'react'
import { useSidebar } from './Layout'

const HEADER_CLASSES =
  'sticky top-0 z-30 h-16 bg-white/80 dark:bg-gray-900/80 backdrop-blur-xl border-b border-gray-200 dark:border-gray-800'

const HEADER_CONTAINER_CLASSES =
  'h-full px-4 sm:px-6 flex items-center justify-between gap-3 sm:gap-4'

const SEARCH_INPUT_BASE_CLASSES =
  'w-full pl-10 pr-4 py-2 bg-gray-100 dark:bg-gray-800 border-0 rounded-xl text-sm text-gray-900 dark:text-white placeholder-gray-500'

const SEARCH_INPUT_FOCUS_CLASSES = 'focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all'

const ICON_BUTTON_CLASSES =
  'p-2 sm:p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors'

export const Header = () => {
  const { theme, toggleTheme } = useTheme()
  const [searchQuery, setSearchQuery] = useState('')
  const { toggle } = useSidebar()

  return (
    <header className={HEADER_CLASSES}>
      <div className={HEADER_CONTAINER_CLASSES}>
        {/* Mobile menu button */}
        <button
          onClick={toggle}
          className="lg:hidden p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
          aria-label="Abrir menu"
        >
          <Menu className="w-5 h-5 text-gray-600 dark:text-gray-400" />
        </button>

        {/* Search */}
        <div className="flex-1 max-w-md">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Buscar..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}

              className={`${SEARCH_INPUT_BASE_CLASSES} ${SEARCH_INPUT_FOCUS_CLASSES}`}
            />
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-1 sm:gap-2">
          {/* Notifications */}
          <button
            className={`relative ${ICON_BUTTON_CLASSES}`}
            aria-label="Notificaciones"
          >
            <Bell className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full" />
          </button>

          {/* Theme toggle */}
          <button
            onClick={toggleTheme}
            className={ICON_BUTTON_CLASSES}
            aria-label="Cambiar tema"
          >
            {theme === 'dark' ? (
              <Sun className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            ) : (
              <Moon className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            )}
          </button>
        </div>
      </div>
    </header>
  )
}

/* eslint-disable max-lines-per-function */
import { useState } from 'react'
import { NavLink, useLocation } from 'react-router-dom'
import {
  LayoutDashboard,
  MessageSquare,
  Users,
  Webhook,
  Settings,
  ChevronLeft,
  ChevronRight,
  ChevronDown,
  Send,
  User,
  LogOut,
  Zap,
  X,
  PanelLeftClose,
  PanelLeft,
} from 'lucide-react'
import { useAuth } from '@/contexts'
import { useSessions } from '@/hooks'
import { useSidebar } from './Layout'

// Tailwind class constants for better line length management
const ACTIVE_NAV_CLASSES = 'bg-primary-600 text-white shadow-lg shadow-primary-600/25'
const INACTIVE_NAV_CLASSES =
  'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-white'
const BADGE_CLASSES =
  'px-2 py-0.5 text-xs font-semibold bg-primary-100 dark:bg-primary-900/50 text-primary-600 dark:text-primary-400 rounded-full'
const ACTIVE_SESSION_CLASSES = 'bg-primary-50 dark:bg-primary-900/20'
const INACTIVE_SESSION_CLASSES = 'hover:bg-gray-100 dark:hover:bg-gray-800'
const ACTIVE_SUBITEM_CLASSES =
  'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400'
const INACTIVE_SUBITEM_CLASSES =
  'text-gray-500 dark:text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-800/50'
const LOGO_CONTAINER_CLASSES =
  'w-9 h-9 bg-gradient-to-br from-primary-500 to-primary-700 rounded-xl flex items-center justify-center shadow-lg shadow-primary-600/20'
const LOGO_CONTAINER_COLLAPSED_CLASSES =
  'w-9 h-9 bg-gradient-to-br from-primary-500 to-primary-700 rounded-xl flex items-center justify-center mx-auto'
const COLLAPSE_BUTTON_CLASSES =
  'hidden lg:flex absolute -right-3 top-20 w-6 h-6 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-full shadow-sm items-center justify-center hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors'

interface NavItemProps {
  to: string
  icon: React.ReactNode
  label: string
  collapsed: boolean
  badge?: number
  onClick?: () => void
}

const NavItem = ({
  to,
  icon,
  label,
  collapsed,
  badge,
  onClick,
}: NavItemProps) => {
  return (
    <NavLink
      to={to}
      onClick={onClick}
      className={({ isActive }) => `
        flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200
        ${isActive ? ACTIVE_NAV_CLASSES : INACTIVE_NAV_CLASSES}
        ${collapsed ? 'justify-center' : ''}
      `}
    >
      <span className="flex-shrink-0">{icon}</span>
      {!collapsed && (
        <>
          <span className="font-medium flex-1">{label}</span>
          {badge !== undefined && badge > 0 && (
            <span className={BADGE_CLASSES}>
              {badge}
            </span>
          )}
        </>
      )}
    </NavLink>
  )
}

interface SessionNavItemProps {
  session: {
    id: string
    session_name: string
    telegram_username?: string
    is_active: boolean
  }
  collapsed: boolean
  onNavigate?: () => void
  isExpanded: boolean
  onToggle: () => void
}

const SessionNavItem = ({
  session,
  collapsed,
  onNavigate,
  isExpanded,
  onToggle,
}: SessionNavItemProps) => {
  const location = useLocation()
  const isActive = location.pathname.includes(session.id)

  if (collapsed) {
    return (
      <NavLink
        to={`/messages/${session.id}`}
        onClick={onNavigate}
        className={`
          flex items-center justify-center p-2 rounded-lg transition-all duration-200
          ${isActive ? ACTIVE_SESSION_CLASSES : INACTIVE_SESSION_CLASSES}
        `}
        title={session.session_name}
      >
        <div className={`w-2 h-2 rounded-full ${session.is_active ? 'bg-green-500' : 'bg-gray-400'}`} />
      </NavLink>
    )
  }

  return (
    <div className="space-y-1">
      {/* Session header - clickable to expand/collapse */}
      <button
        onClick={onToggle}
        className={`
          w-full flex items-center gap-2 px-3 py-2 rounded-lg transition-all duration-200
          ${isActive ? ACTIVE_SESSION_CLASSES : INACTIVE_SESSION_CLASSES}
        `}
      >
        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${session.is_active ? 'bg-green-500' : 'bg-gray-400'}`} />
        <span
          className={`text-sm font-medium truncate flex-1 text-left ${
            isActive ? 'text-primary-600 dark:text-primary-400' : 'text-gray-700 dark:text-gray-300'
          }`}
        >
          {session.session_name}
        </span>
        {session.is_active && (
          <ChevronDown
            className={`w-4 h-4 text-gray-400 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`}
          />
        )}
      </button>

      {/* Expandable menu items */}
      {session.is_active && isExpanded && (
        <div className="pl-5 space-y-0.5 overflow-hidden animate-accordion-down">
          <NavLink
            to={`/messages/${session.id}`}
            onClick={onNavigate}
            className={({ isActive }) => `
              flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
              ${isActive ? ACTIVE_SUBITEM_CLASSES : INACTIVE_SUBITEM_CLASSES}
            `}
          >
            <Send className="w-3.5 h-3.5" />
            <span>Mensajes</span>
          </NavLink>
          <NavLink
            to={`/chats/${session.id}`}
            onClick={onNavigate}
            className={({ isActive }) => `
              flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
              ${isActive ? ACTIVE_SUBITEM_CLASSES : INACTIVE_SUBITEM_CLASSES}
            `}
          >
            <MessageSquare className="w-3.5 h-3.5" />
            <span>Chats</span>
          </NavLink>
          <NavLink
            to={`/contacts/${session.id}`}
            onClick={onNavigate}
            className={({ isActive }) => `
              flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
              ${isActive ? ACTIVE_SUBITEM_CLASSES : INACTIVE_SUBITEM_CLASSES}
            `}
          >
            <Users className="w-3.5 h-3.5" />
            <span>Contacts</span>
          </NavLink>
          <NavLink
            to={`/webhooks/${session.id}`}
            onClick={onNavigate}
            className={({ isActive }) => `
              flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
              ${isActive ? ACTIVE_SUBITEM_CLASSES : INACTIVE_SUBITEM_CLASSES}
            `}
          >
            <Webhook className="w-3.5 h-3.5" />
            <span>Webhooks</span>
          </NavLink>
        </div>
      )}
    </div>
  )
}

export const Sidebar = () => {
  const [expandedSessions, setExpandedSessions] = useState<Set<string>>(new Set())
  const { user, logout } = useAuth()
  const { data: sessions } = useSessions()
  const { isOpen, setIsOpen, isCollapsed, toggleCollapse } = useSidebar()
  const location = useLocation()

  const activeSessions = sessions?.filter(s => s.is_active).length || 0

  // Close sidebar on mobile when navigating
  const handleMobileNavigate = () => {
    if (window.innerWidth < 1024) {
      setIsOpen(false)
    }
  }

  // Toggle session expansion
  const toggleSession = (sessionId: string) => {
    setExpandedSessions(prev => {
      const next = new Set(prev)
      if (next.has(sessionId)) {
        next.delete(sessionId)
      } else {
        next.add(sessionId)
      }
      return next
    })
  }

  // Auto-expand session if currently viewing it
  const isSessionExpanded = (sessionId: string) => {
    if (location.pathname.includes(sessionId)) {
      return true
    }
    return expandedSessions.has(sessionId)
  }

  return (
    <aside
      className={`
        fixed left-0 top-0 h-screen bg-white dark:bg-gray-900 border-r border-gray-200 dark:border-gray-800
        flex flex-col transition-all duration-300 z-40
        ${isCollapsed ? 'w-[72px]' : 'w-64'}
        ${isOpen ? 'translate-x-0' : '-translate-x-full'}
        lg:translate-x-0
      `}
    >
      {/* Logo */}
      <div className="h-16 flex items-center justify-between px-4 border-b border-gray-200 dark:border-gray-800">
        {!isCollapsed && (
          <div className="flex items-center gap-3">
            <div className={LOGO_CONTAINER_CLASSES}>
              <Zap className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="font-bold text-gray-900 dark:text-white">Telegram</h1>
              <p className="text-xs text-gray-500 dark:text-gray-500">API Manager</p>
            </div>
          </div>
        )}
        {isCollapsed && (
          <div className={LOGO_CONTAINER_COLLAPSED_CLASSES}>
            <Zap className="w-5 h-5 text-white" />
          </div>
        )}
        {/* Close button for mobile - only when not collapsed */}
        {!isCollapsed && (
          <button
            onClick={() => setIsOpen(false)}
            className="lg:hidden p-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
          >
            <X className="w-5 h-5 text-gray-500" />
          </button>
        )}
