                    className={`p-4 rounded-lg border-2 transition-all ${
                      authMethod === 'tdata'
                        ? 'border-primary-600 bg-primary-50 dark:bg-primary-900/20'
                        : 'border-gray-200 dark:border-gray-700 hover:border-primary-300 dark:hover:border-primary-700'
                    }`}
                  >
                    <Database
                      className={`w-6 h-6 mx-auto mb-2 ${
                        authMethod === 'tdata' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'
                      }`}
                    />
                    <p className="text-sm font-medium text-gray-900 dark:text-white">TData</p>
                    <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                      Importar desde Desktop
                    </p>
                  </button>
                </div>
              </div>

              {authMethod === 'sms' && (
                <Input
                  label="Número de Teléfono"
                  type="tel"
                  placeholder="+573001234567"
                  value={formData.phone}
                  onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                  disabled={createSession.isPending}
                />
              )}

              {authMethod === 'qr' && (
                <Alert variant="info">
                  <p className="text-sm">
                    Se generará un código QR que podrás escanear desde tu aplicación de Telegram.
                    El QR se regenerará automáticamente si expira (máximo 3 intentos).
                  </p>
                </Alert>
              )}

              {authMethod === 'tdata' && (
                <Alert variant="info">
                  <p className="text-sm">
                    Importa una sesión existente desde Telegram Desktop. Necesitas exportar
                    los archivos TData desde tu instalación de Telegram Desktop primero.
                  </p>
                </Alert>
