  'w-full flex items-center gap-3 px-3 py-2.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors'

const textareaClasses =
  'w-full px-4 py-2.5 bg-gray-100 dark:bg-gray-800 border-0 rounded-2xl text-gray-900 dark:text-white placeholder-gray-500 resize-none focus:outline-none focus:ring-2 focus:ring-primary-500 disabled:opacity-50 max-h-32 text-sm sm:text-base'

const sendButtonClasses =
  'p-2.5 rounded-full bg-primary-600 hover:bg-primary-700 text-white transition-colors disabled:opacity-50 disabled:cursor-not-allowed shrink-0'

export const MessageInput = ({ sessionId, chatId, onMessageSent }: MessageInputProps) => {
  const [message, setMessage] = useState('')
  const [attachment, setAttachment] = useState<Attachment | null>(null)
  const [showAttachMenu, setShowAttachMenu] = useState(false)
  const [isUploading, setIsUploading] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)
  const attachTypeRef = useRef<FileType | null>(null)

  const toast = useToast()

  const sendTextMutation = useSendTextMessage()
  const sendPhotoMutation = useSendPhotoMessage()
  const sendVideoMutation = useSendVideoMessage()
  const sendAudioMutation = useSendAudioMessage()
  const sendFileMutation = useSendFileMessage()

  const isSending =
    sendTextMutation.isPending ||
    sendPhotoMutation.isPending ||
    sendVideoMutation.isPending ||
    sendAudioMutation.isPending ||
    sendFileMutation.isPending ||
    isUploading

  const handleAttachClick = (type: FileType) => {
    attachTypeRef.current = type
    if (fileInputRef.current) {
      fileInputRef.current.accept = ACCEPTED_TYPES[type] || '*/*'
      fileInputRef.current.click()
    }
    setShowAttachMenu(false)
  }

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0]
      if (!file) return

      const type = attachTypeRef.current
      if (!type) return

      // Validate file
      const validation = validateFile(file, type)
      if (!validation.valid) {
        toast.error('Archivo no valido', validation.error || 'Error al validar')
        e.target.value = ''
        return
      }

      // Create preview for images
      let preview: string | undefined
      if (type === 'image') {
        preview = URL.createObjectURL(file)
      }

      setAttachment({ type, file, preview })
      e.target.value = '' // Reset input
    },
    [toast]
  )

  const removeAttachment = () => {
    if (attachment?.preview) {
      URL.revokeObjectURL(attachment.preview)
    }
    setAttachment(null)
  }

  const handleSend = async () => {
    if (!message.trim() && !attachment) return

    const to = chatId.toString()

    try {
      if (attachment) {
        setIsUploading(true)

        // Upload file
        const uploadResult = await uploadFile(attachment.file, attachment.type)

        if (!uploadResult.success || !uploadResult.url) {
          toast.error('Error de subida', uploadResult.error || 'No se pudo subir el archivo')
          setIsUploading(false)
          return
        }

        // The URL could be a base64 data URL or a server URL
        // If it's base64, construct a proper URL path
        const fileUrl = uploadResult.url

        // If the uploadFile returned a base64, we need a proper URL
        // In production with real upload endpoint, the URL would be returned from server
        if (uploadResult.url.startsWith('data:')) {
          // For base64, use the constructed URL (backend should handle base64 or we need real upload)
          // For now, let's assume the backend supports base64 or we'll show an error
          toast.warning('Aviso', 'Subiendo archivo... Por favor espera.')
        }

        // Send message with media
        const caption = message.trim() || undefined

        switch (attachment.type) {
          case 'image':
            await sendPhotoMutation.mutateAsync({
              sessionId,
              data: { to, photo_url: fileUrl, caption },
            })
            break
          case 'video':
            await sendVideoMutation.mutateAsync({
              sessionId,
              data: { to, video_url: fileUrl, caption },
            })
            break
          case 'audio':
            await sendAudioMutation.mutateAsync({
              sessionId,
              data: { to, audio_url: fileUrl, caption },
            })
            break
          case 'file':
            await sendFileMutation.mutateAsync({
              sessionId,
              data: { to, file_url: fileUrl, caption },
            })
            break
        }

        toast.success('Enviado', 'El mensaje se envio correctamente')
        removeAttachment()
      } else {
        // Send text message
        await sendTextMutation.mutateAsync({
          sessionId,
          data: { to, text: message.trim() },
        })
        toast.success('Enviado', 'Mensaje enviado')
      }

      setMessage('')
      onMessageSent?.()
    } catch (_error) {
      toast.error('Error', 'No se pudo enviar el mensaje')
    } finally {
      setIsUploading(false)
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  return (
    <div className="border-t border-gray-200 dark:border-gray-700 p-3 sm:p-4 bg-white dark:bg-gray-900">
      {/* Attachment Preview */}
      {attachment && (
        <div className="mb-3 p-3 bg-gray-100 dark:bg-gray-800 rounded-xl">
          <div className="flex items-center gap-3">
            {attachment.type === 'image' && attachment.preview ? (
              <img
                src={attachment.preview}
                alt="Preview"
                className="w-16 h-16 object-cover rounded-lg"
              />
            ) : (
              <div className="w-12 h-12 bg-primary-100 dark:bg-primary-900/30 rounded-lg flex items-center justify-center">
                {attachment.type === 'image' && <Image className="w-6 h-6 text-primary-600" />}
                {attachment.type === 'video' && <Video className="w-6 h-6 text-primary-600" />}
                {attachment.type === 'audio' && <Music className="w-6 h-6 text-primary-600" />}
                {attachment.type === 'file' && <FileText className="w-6 h-6 text-primary-600" />}
              </div>
            )}
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-gray-900 dark:text-white truncate">
                {attachment.file.name}
              </p>
              <p className="text-xs text-gray-500">
                {formatFileSize(attachment.file.size)}
              </p>
            </div>
            <button
              onClick={removeAttachment}
              className="p-1.5 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
            >
              <X className="w-4 h-4 text-gray-500" />
            </button>
          </div>
        </div>
      )}

      {/* Input Area */}
      <div className="flex items-end gap-2">
        {/* Attachment Button */}
        <div className="relative">
          <button
            onClick={() => setShowAttachMenu(!showAttachMenu)}
            disabled={isSending}
            className="p-2.5 rounded-full bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
          >
            {showAttachMenu ? (
              <X className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            ) : (
              <Plus className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            )}
          </button>

          {/* Attachment Menu */}
          {showAttachMenu && (
            <>
              {/* Backdrop */}
              <div
                className="fixed inset-0 z-10"
                onClick={() => setShowAttachMenu(false)}
              />
              <div className={attachmentMenuClasses}>
                <button onClick={() => handleAttachClick('image')} className={menuItemClasses}>
                  <div className="w-8 h-8 bg-blue-100 dark:bg-blue-900/30 rounded-full flex items-center justify-center">
                    <Image className="w-4 h-4 text-blue-600 dark:text-blue-400" />
                  </div>
                  <span className="text-sm text-gray-700 dark:text-gray-300">Imagen</span>
                </button>
                <button onClick={() => handleAttachClick('video')} className={menuItemClasses}>
                  <div className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 rounded-full flex items-center justify-center">
                    <Video className="w-4 h-4 text-purple-600 dark:text-purple-400" />
                  </div>
                  <span className="text-sm text-gray-700 dark:text-gray-300">Video</span>
                </button>
                <button onClick={() => handleAttachClick('audio')} className={menuItemClasses}>
                  <div className="w-8 h-8 bg-orange-100 dark:bg-orange-900/30 rounded-full flex items-center justify-center">
                    <Music className="w-4 h-4 text-orange-600 dark:text-orange-400" />
                  </div>
                  <span className="text-sm text-gray-700 dark:text-gray-300">Audio</span>
                </button>
                <button onClick={() => handleAttachClick('file')} className={menuItemClasses}>
                  <div className="w-8 h-8 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center">
                    <FileText className="w-4 h-4 text-green-600 dark:text-green-400" />
                  </div>
                  <span className="text-sm text-gray-700 dark:text-gray-300">Documento</span>
                </button>
              </div>
            </>
          )}
        </div>

        {/* Hidden file input */}
        <input
          ref={fileInputRef}
          type="file"
          onChange={handleFileChange}
          className="hidden"
        />

        {/* Text Input */}
        <div className="flex-1">
          <textarea
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Escribe un mensaje..."
            disabled={isSending}
            rows={1}
            className={textareaClasses}
            style={{ minHeight: '44px' }}
          />
        </div>

        {/* Send Button */}
        <button
          onClick={handleSend}
          disabled={isSending || (!message.trim() && !attachment)}
          className={sendButtonClasses}
        >
          {isSending ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <Send className="w-5 h-5" />
          )}
        </button>
      </div>

      {/* Hint - only show on desktop */}
      <p className="hidden sm:block mt-2 text-xs text-gray-400 dark:text-gray-500 text-center">
        Enter para enviar, Shift+Enter para nueva linea
      </p>
    </div>
  )
}

import { useState, useMemo, useCallback, useEffect, useRef } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import {
  ArrowLeft,
  Loader2,
  AlertCircle,
  Users,
  Phone,
  Clock,
  UserCheck,
  UserX,
  Search,
  X,
  Database,
  ChevronDown,
} from 'lucide-react'
import { Layout } from '@/components/layout'
import { Button, Alert, Card } from '@/components/common'
import { useInfiniteContacts, useSession } from '@/hooks'
import { Contact } from '@/api/chats.api'

// Tailwind class constants
const searchInputClasses =
  'w-full pl-10 pr-10 py-3 bg-white dark:bg-gray-800 border ' +
  'border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 ' +
  'dark:text-white placeholder-gray-500 focus:outline-none focus:ring-2 ' +
  'focus:ring-primary-500 focus:border-transparent transition-shadow'

const clearButtonClasses =
  'absolute right-3 top-1/2 -translate-y-1/2 p-1 rounded-full ' +
  'hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors'

const emptyStateIconContainerClasses =
  'inline-flex items-center justify-center w-16 h-16 ' +
  'bg-gray-100 dark:bg-gray-800 rounded-full mb-4'

const onlineAvatarClasses =
  'bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400'

const offlineAvatarClasses =
  'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400'

const primaryBadgeClasses =
  'inline-flex items-center px-3 py-1.5 rounded-lg text-sm font-medium ' +
  'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-400'

const onlineStatusBadgeClasses =
  'inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ' +
  'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400'

const cacheBadgeClasses =
  'inline-flex items-center px-3 py-1.5 rounded-lg text-sm font-medium ' +
  'bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-400'

const mutualBadgeClasses =
  'flex items-center gap-1 text-xs text-green-600 dark:text-green-400 ' +
  'bg-green-50 dark:bg-green-900/20 px-2 py-0.5 rounded-full'

const blockedBadgeClasses =
  'flex items-center gap-1 text-xs text-red-600 dark:text-red-400 ' +
  'bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded-full'

export const ContactsPage = () => {
  const { sessionId } = useParams<{ sessionId: string }>()
  const navigate = useNavigate()
  const [searchTerm, setSearchTerm] = useState('')
  const [debouncedSearch, setDebouncedSearch] = useState('')
  const loadMoreRef = useRef<HTMLDivElement>(null)

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchTerm)
    }, 300)
    return () => clearTimeout(timer)
  }, [searchTerm])

  const { data: sessionData, isLoading: sessionLoading } = useSession(sessionId!)
  const {
    data: contactsData,
    isLoading: contactsLoading,
    error,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useInfiniteContacts(sessionId!, debouncedSearch || undefined, 50)

  const isLoading = sessionLoading || contactsLoading

  // Flatten all pages into a single array
  const contacts = useMemo(() => {
    if (!contactsData?.pages) return []
    return contactsData.pages.flatMap((page) => page.contacts)
  }, [contactsData])

  // Get total count and cache status from first page
  const totalCount = contactsData?.pages[0]?.total_count || 0
  const fromCache = contactsData?.pages[0]?.from_cache || false

  // Filter contacts locally for instant feedback
  const filteredContacts = useMemo(() => {
    if (!searchTerm) return contacts
    const term = searchTerm.toLowerCase()
    return contacts.filter(
      (contact) =>
        contact.first_name?.toLowerCase().includes(term) ||
        contact.last_name?.toLowerCase().includes(term) ||
        contact.username?.toLowerCase().includes(term) ||
        contact.phone?.includes(term)
    )
  }, [contacts, searchTerm])

  // Intersection observer for infinite scroll
  const handleObserver = useCallback(
    (entries: IntersectionObserverEntry[]) => {
      const target = entries[0]
      if (target.isIntersecting && hasNextPage && !isFetchingNextPage) {
        fetchNextPage()
      }
    },
    [fetchNextPage, hasNextPage, isFetchingNextPage]
  )

  useEffect(() => {
    const option = {
      root: null,
      rootMargin: '100px',
      threshold: 0,
    }
    const observer = new IntersectionObserver(handleObserver, option)
    if (loadMoreRef.current) observer.observe(loadMoreRef.current)
    return () => observer.disconnect()
  }, [handleObserver])

  if (!sessionId) {
    return (
      <Layout>
        <Alert variant="error">ID de sesion no valido</Alert>
      </Layout>
    )
  }

  if (isLoading && !contactsData) {
    return (
      <Layout>
        <div className="flex flex-col items-center justify-center py-12 gap-3">
          <Loader2 className="w-8 h-8 animate-spin text-primary-600" />
          <p className="text-sm text-gray-500 dark:text-gray-400">Cargando contacts...</p>
        </div>
      </Layout>
    )
  }

  if (!sessionData) {
    return (
      <Layout>
        <Alert variant="error">Sesion no encontrada</Alert>
      </Layout>
    )
  }

  const session = sessionData.session

  if (!session.is_active) {
    return (
      <Layout>
        <div className="max-w-2xl mx-auto text-center py-12">
          <AlertCircle className="w-16 h-16 text-yellow-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
            Sesion no activa
          </h2>
          <p className="text-gray-600 dark:text-gray-400 mb-6">
            Esta sesion no esta activa. Por favor, verifica la sesion primero.
          </p>
          <Button variant="primary" onClick={() => navigate('/dashboard')}>
            <ArrowLeft className="w-4 h-4 mr-2" />
            Volver al Dashboard
          </Button>
        </div>
      </Layout>
    )
  }

  const getStatusColor = (status?: string) => {
    if (!status) return 'text-gray-500'
    switch (status.toLowerCase()) {
      case 'online':
        return 'text-green-600 dark:text-green-400'
      case 'recently':
        return 'text-blue-600 dark:text-blue-400'
      case 'offline':
        return 'text-gray-500 dark:text-gray-500'
      default:
        return 'text-gray-500 dark:text-gray-500'
    }
  }

  const getStatusBadge = (status?: string) => {
    if (!status) return null
    const statusLower = status.toLowerCase()
    if (statusLower === 'online') {
      return (
        <span className={onlineStatusBadgeClasses}>
          En linea
        </span>
      )
    }
    return null
  }

  const formatLastSeen = (lastSeenAt?: string) => {
    if (!lastSeenAt) return null
    const date = new Date(lastSeenAt)
    // Check for zero date
    if (date.getFullYear() < 2000) return null
    const now = new Date()
    const diff = now.getTime() - date.getTime()
    const minutes = Math.floor(diff / (1000 * 60))
    const hours = Math.floor(diff / (1000 * 60 * 60))
    const days = Math.floor(hours / 24)

    if (minutes < 1) return 'Justo ahora'
    if (minutes < 60) return `Hace ${minutes} min`
    if (hours < 24) return `Hace ${hours}h`
    if (days === 1) return 'Ayer'
    if (days < 7) return `Hace ${days} dias`
    return date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })
  }

  return (
    <Layout>
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
            <div className="flex items-center gap-3">
              <Button variant="ghost" onClick={() => navigate('/dashboard')} className="shrink-0">
                <ArrowLeft className="w-4 h-4" />
              </Button>
              <div className="min-w-0">
                <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white truncate">
                  Contacts
                </h1>
                <p className="text-sm text-gray-600 dark:text-gray-400 truncate">
                  {session.phone_number || session.session_name}
                </p>
              </div>
            </div>

            {/* Stats badges */}
            <div className="flex items-center gap-2 flex-wrap">
              <span className={primaryBadgeClasses}>
                <Users className="w-4 h-4 mr-1.5" />
                {totalCount.toLocaleString()} contacts
              </span>
              {fromCache && (
                <span className={cacheBadgeClasses}>
                  <Database className="w-4 h-4 mr-1.5" />
                  Cache
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Search bar */}
        <div className="mb-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="Buscar por nombre, usuario o telefono..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className={searchInputClasses}
            />
            {searchTerm && (
              <button
                onClick={() => setSearchTerm('')}
                className={clearButtonClasses}
              >
                <X className="w-4 h-4 text-gray-400" />
              </button>
            )}
          </div>
          {searchTerm && (
            <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">
              {filteredContacts.length} resultados para "{searchTerm}"
            </p>
          )}
        </div>

        {error && (
          <Alert variant="error" className="mb-6">
            <div className="flex items-center gap-2">
              <AlertCircle className="w-5 h-5" />
              <span>Error al cargar los contacts. Intenta nuevamente.</span>
            </div>
          </Alert>
        )}

        {filteredContacts.length === 0 && !isLoading && (
          <div className="text-center py-12">
            <div className={emptyStateIconContainerClasses}>
              <Users className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
              {searchTerm ? 'Sin resultados' : 'No hay contactos'}
            </h3>
            <p className="text-gray-600 dark:text-gray-400">
              {searchTerm
                ? `No se encontraron contacts para "${searchTerm}"`
                : 'No se encontraron contacts en esta sesion'}
            </p>
          </div>
        )}

        {filteredContacts.length > 0 && (
          <>
            {/* Contacts grid */}
            <div className="grid gap-3 sm:gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
              {filteredContacts.map((contact: Contact) => (
                <Card key={contact.id} hover className="p-4">
                  <div className="flex items-start gap-3">
                    {/* Avatar */}
                    <div className="shrink-0">
                      <div
                        className={`w-12 h-12 rounded-full flex items-center justify-center text-lg font-semibold ${
                          contact.status?.toLowerCase() === 'online'
                            ? onlineAvatarClasses
                            : offlineAvatarClasses
                        }`}
                      >
                        {contact.first_name?.charAt(0).toUpperCase() || '?'}
                      </div>
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                          {contact.first_name} {contact.last_name || ''}
                        </h3>
                        {getStatusBadge(contact.status)}
                      </div>

                      {contact.username && (
                        <p className="text-sm text-primary-600 dark:text-primary-400 truncate">
                          @{contact.username}
                        </p>
                      )}

                      {contact.phone && (
                        <div className="flex items-center gap-1.5 mt-1.5 text-sm text-gray-600 dark:text-gray-400">
                          <Phone className="w-3.5 h-3.5 shrink-0" />
                          <span className="truncate">+{contact.phone}</span>
                        </div>
                      )}

                      {/* Status and last seen */}
                      <div className="flex items-center gap-3 mt-2 flex-wrap">
                        {contact.status && contact.status.toLowerCase() !== 'online' && (
                          <span className={`text-xs ${getStatusColor(contact.status)}`}>
                            {contact.status === 'recently' ? 'Reciente' : contact.status}
                          </span>
                        )}
                        {formatLastSeen(contact.last_seen_at) && (
                          <div className="flex items-center gap-1 text-xs text-gray-500 dark:text-gray-500">
                            <Clock className="w-3 h-3" />
                            <span>{formatLastSeen(contact.last_seen_at)}</span>
                          </div>
                        )}
                      </div>

                      {/* Badges */}
                      <div className="flex items-center gap-2 mt-2">
                        {contact.is_mutual && (
                          <div className={mutualBadgeClasses}>
                            <UserCheck className="w-3 h-3" />
                            <span>Mutuo</span>
                          </div>
                        )}
                        {contact.is_blocked && (
                          <div className={blockedBadgeClasses}>
                            <UserX className="w-3 h-3" />
                            <span>Bloqueado</span>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </Card>
              ))}
            </div>

            {/* Load more / Infinite scroll trigger */}
            <div ref={loadMoreRef} className="mt-6 flex justify-center">
              {isFetchingNextPage ? (
                <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400">
                  <Loader2 className="w-5 h-5 animate-spin" />
                  <span>Cargando mas contacts...</span>
                </div>
              ) : hasNextPage ? (
                <Button
                  variant="secondary"
                  onClick={() => fetchNextPage()}
                  className="flex items-center gap-2"
                >
                  <ChevronDown className="w-4 h-4" />
                  Cargar mas
                </Button>
              ) : filteredContacts.length > 0 && contacts.length >= 50 ? (
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  Has visto todos los contacts
                </p>
              ) : null}
            </div>
          </>
        )}
      </div>
    </Layout>
  )
}

import { useState } from 'react'
import { Plus, Loader2, AlertCircle, Smartphone, Activity } from 'lucide-react'
import { Layout } from '@/components/layout'
import { Button, Alert, Card } from '@/components/common'
import { useSessions } from '@/hooks'
import { SessionCard } from './components/SessionCard'
import { CreateSessionModal, VerifySMSModal, QRCodeModal } from '@/components/sessions'
import type { CreateSessionResponse } from '@/types'

export const DashboardPage = () => {
  const { data: sessions, isLoading, error, refetch } = useSessions()

  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showVerifySMS, setShowVerifySMS] = useState(false)
  const [showQRCode, setShowQRCode] = useState(false)

  const [currentSession, setCurrentSession] = useState<{
    id: string
    phone?: string
    qr?: string
  } | null>(null)

  const handleCreateSuccess = (sessionId: string, response: CreateSessionResponse) => {
    setShowCreateModal(false)

    if (response.phone_code_hash) {
      // Flujo SMS
      setCurrentSession({ id: sessionId, phone: response.session.phone_number })
      setShowVerifySMS(true)
    } else if (response.qr_image_base64) {
      // Flujo QR
      setCurrentSession({ id: sessionId, qr: response.qr_image_base64 })
      setShowQRCode(true)
    }
  }

  const handleVerifySuccess = () => {
    setShowVerifySMS(false)
    setCurrentSession(null)
    refetch()
  }

  const handleQRSuccess = () => {
    setShowQRCode(false)
    setCurrentSession(null)
    refetch()
  }

  // Stats
  const totalSessions = sessions?.length || 0
  const activeSessions = sessions?.filter((s) => s.is_active).length || 0
  const pendingSessions = sessions?.filter((s) => !s.is_active && s.auth_state !== 'failed').length || 0

  return (
    <Layout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
              Dashboard
            </h1>
            <p className="text-gray-600 dark:text-gray-400 mt-1">
              Gestiona tus sesiones de Telegram
            </p>
          </div>
          <Button
            variant="primary"
            className="w-full sm:w-auto"
            onClick={() => setShowCreateModal(true)}
          >
            <Plus className="w-4 h-4 mr-2" />
            Nueva Sesion
          </Button>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4">
          <Card className="flex items-center gap-3 sm:gap-4">
            <div className="p-2.5 sm:p-3 bg-primary-100 dark:bg-primary-900/30 rounded-xl flex-shrink-0">
              <Smartphone className="w-5 h-5 sm:w-6 sm:h-6 text-primary-600 dark:text-primary-400" />
            </div>
            <div className="min-w-0">
              <p className="text-xs sm:text-sm text-gray-500 dark:text-gray-400">Total Sesiones</p>
              <p className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white">{totalSessions}</p>
            </div>
          </Card>

          <Card className="flex items-center gap-3 sm:gap-4">
            <div className="p-2.5 sm:p-3 bg-green-100 dark:bg-green-900/30 rounded-xl flex-shrink-0">
              <Activity className="w-5 h-5 sm:w-6 sm:h-6 text-green-600 dark:text-green-400" />
            </div>
            <div className="min-w-0">
              <p className="text-xs sm:text-sm text-gray-500 dark:text-gray-400">Activas</p>
              <p className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white">{activeSessions}</p>
            </div>
          </Card>

          <Card className="flex items-center gap-3 sm:gap-4 sm:col-span-2 lg:col-span-1">
            <div className="p-2.5 sm:p-3 bg-yellow-100 dark:bg-yellow-900/30 rounded-xl flex-shrink-0">
              <AlertCircle className="w-5 h-5 sm:w-6 sm:h-6 text-yellow-600 dark:text-yellow-400" />
            </div>
            <div className="min-w-0">
              <p className="text-xs sm:text-sm text-gray-500 dark:text-gray-400">Pendientes</p>
              <p className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white">{pendingSessions}</p>
            </div>
          </Card>
        </div>

        {/* Loading */}
        {isLoading && (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-8 h-8 animate-spin text-primary-600" />
          </div>
        )}

        {/* Error */}
        {error && (
          <Alert variant="error">
            <div className="flex items-center gap-2">
              <AlertCircle className="w-5 h-5" />
              <span>Error al cargar las sesiones. Intenta nuevamente.</span>
            </div>
          </Alert>
        )}

        {/* Empty State */}
        {sessions && sessions.length === 0 && (
          <Card className="p-12 text-center">
            <div className="inline-flex items-center justify-center w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full mb-6">
              <Smartphone className="w-10 h-10 text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
              No hay sesiones
            </h3>
            <p className="text-gray-600 dark:text-gray-400 mb-6 max-w-sm mx-auto">
              Crea tu primera sesion de Telegram para comenzar a enviar mensajes
            </p>
            <Button variant="primary" onClick={() => setShowCreateModal(true)}>
              <Plus className="w-4 h-4 mr-2" />
              Crear Sesion
            </Button>
          </Card>
        )}

        {/* Sessions List */}
        {sessions && sessions.length > 0 && (
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
              Sesiones ({sessions.length})
            </h2>
            <div className="grid gap-4">
              {sessions.map((session) => (
                <SessionCard key={session.id} session={session} />
              ))}
            </div>
          </div>
        )}

        {/* Modals */}
        <CreateSessionModal
          isOpen={showCreateModal}
          onClose={() => setShowCreateModal(false)}
          onSuccess={handleCreateSuccess}
        />

        {currentSession && showVerifySMS && (
          <VerifySMSModal
            isOpen={showVerifySMS}
            onClose={() => setShowVerifySMS(false)}
            sessionId={currentSession.id}
            phoneNumber={currentSession.phone || ''}
            onSuccess={handleVerifySuccess}
          />
        )}

        {currentSession && showQRCode && (
          <QRCodeModal
            isOpen={showQRCode}
            onClose={() => setShowQRCode(false)}
            sessionId={currentSession.id}
            qrImage={currentSession.qr || ''}
            onSuccess={handleQRSuccess}
          />
        )}
      </div>
    </Layout>
  )
}

import { useState } from 'react'
import { Button, Input, Alert } from '@/components/common'
import { useSendTextMessage } from '@/hooks'
import { useToast } from '@/contexts'
import { ApiException } from '@/types'
import { Send } from 'lucide-react'

interface SendTextFormProps {
  sessionId: string
}

// Tailwind classes for textarea
const TEXTAREA_CLASSES = 'w-full px-4 py-3 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all resize-none'

export const SendTextForm = ({ sessionId }: SendTextFormProps) => {
  const toast = useToast()
  const [to, setTo] = useState('')
  const [text, setText] = useState('')
  const [error, setError] = useState('')

  const sendMessage = useSendTextMessage()

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')

    if (!to.trim()) {
      setError('El destinatario es requerido')
      return
    }

    if (!text.trim()) {
      setError('El mensaje es requerido')
      return
    }

    try {
      const response = await sendMessage.mutateAsync({
        sessionId,
        data: { to: to.trim(), text: text.trim() },
      })

      toast.success('Mensaje enviado', `Job ID: ${response.job_id}`)
      setTo('')
      setText('')
    } catch (err) {
      if (err instanceof ApiException) {
        setError(err.message)
      } else {
        setError('Error al enviar el mensaje')
      }
    }
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {error && <Alert variant="error">{error}</Alert>}

      <Input
        label="Destinatario"
        type="text"
        placeholder="@username, +573001234567 o ID de chat"
        value={to}
        onChange={(e) => setTo(e.target.value)}
        disabled={sendMessage.isPending}
      />

      <div>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
          Mensaje
        </label>
        <textarea
          className={TEXTAREA_CLASSES}
          rows={6}
          placeholder="Escribe tu mensaje aqui..."
          value={text}
          onChange={(e) => setText(e.target.value)}
          disabled={sendMessage.isPending}
        />
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-2">
          {text.length} caracteres
        </p>
      </div>

      <Button
        type="submit"
        variant="primary"
        isLoading={sendMessage.isPending}
        fullWidth
        className="h-12"
      >
        <Send className="w-4 h-4 mr-2" />
        Enviar Mensaje
      </Button>
    </form>
  )
}

