              <p className="text-xs text-gray-500 dark:text-gray-400">ID: {poolSession.telegram_id}</p>
            </div>
          </div>
          <span
            className={`${STATUS_BADGE_BASE} ${
              poolSession.is_connected ? STATUS_BADGE_CONNECTED : STATUS_BADGE_DISCONNECTED
            }`}
          >
            {poolSession.is_connected ? 'Conectado' : 'Desconectado'}
          </span>
        </div>
      ))}
    </div>
  </Card>
)

// Events Info Card Component
const EventsInfoCard = () => (
  <Card className={CONFIG_CARD}>
    <h3 className="font-semibold text-gray-900 dark:text-white mb-4">Eventos disponibles</h3>
    <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
      {WEBHOOK_EVENTS.map((event) => (
        <div key={event.id} className={EVENT_CARD}>
          <div className="flex items-center gap-2 mb-1">
            <Zap className="w-4 h-4 text-primary-500" />
            <p className={EVENT_LABEL}>{event.label}</p>
          </div>
          <p className={EVENT_DESCRIPTION}>{event.description}</p>
          <p className={EVENT_ID}>{event.id}</p>
        </div>
      ))}
    </div>
  </Card>
)

export const WebhooksPage = () => {
  const { sessionId } = useParams<{ sessionId: string }>()
  const navigate = useNavigate()
  const toast = useToast()

  const { data: session, isLoading: sessionLoading } = useSession(sessionId!)
  const webhook = useWebhook(sessionId!)

  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
  const [showSecret, setShowSecret] = useState(false)
  const [autoStart, setAutoStart] = useState(true)

  // Form state
  const [formData, setFormData] = useState<WebhookCreateRequest>({
    url: '',
    events: ['message.new'],
    secret: '',
    timeout_ms: 5000,
    max_retries: 3,
  })

  const handleCreateWebhook = async () => {
    if (!formData.url) {
      toast.error('Error', 'La URL es requerida')
      return
    }

    try {
      await webhook.create(formData, autoStart)
      toast.success(
        'Webhook creado',
        autoStart
          ? 'El webhook ha sido creado y esta escuchando eventos'
          : 'El webhook ha sido configurado correctamente'
      )
      setShowCreateModal(false)
      resetForm()
    } catch (error: unknown) {
      toast.error('Error', getErrorMessage(error))
    }
  }

  const handleDeleteWebhook = async () => {
    try {
      await webhook.delete()
      toast.success('Webhook eliminado', 'El webhook ha sido eliminado')
      setShowDeleteConfirm(false)
    } catch (error: unknown) {
      toast.error('Error', getErrorMessage(error))
    }
  }

  const handleStartWebhook = async () => {
    try {
      await webhook.start()
      toast.success('Webhook iniciado', 'El webhook esta escuchando eventos')
    } catch (error: unknown) {
      toast.error('Error', getErrorMessage(error))
    }
  }

  const handleStopWebhook = async () => {
    try {
      await webhook.stop()
      toast.success('Webhook detenido', 'El webhook ha dejado de escuchar')
    } catch (error: unknown) {
      toast.error('Error', getErrorMessage(error))
    }
  }

  const toggleEvent = (eventId: string) => {
    setFormData((prev) => ({
      ...prev,
      events: prev.events?.includes(eventId)
        ? prev.events.filter((e) => e !== eventId)
        : [...(prev.events || []), eventId],
    }))
  }

  const resetForm = () => {
    setFormData({
      url: '',
      events: ['message.new'],
      secret: '',
      timeout_ms: 5000,
      max_retries: 3,
    })
    setAutoStart(true)
  }

  const selectAllEvents = () => {
    setFormData((prev) => ({
      ...prev,
      events: WEBHOOK_EVENTS.map((e) => e.id),
    }))
  }

  const clearAllEvents = () => {
    setFormData((prev) => ({
      ...prev,
      events: [],
    }))
  }

  if (!sessionId) {
    return (
      <Layout>
        <Alert variant="error">ID de sesion no valido</Alert>
      </Layout>
    )
  }

  if (sessionLoading || webhook.isLoading) {
    return (
      <Layout>
        <div className={LOADING_CONTAINER}>
          <Loader2 className={LOADING_SPINNER} />
        </div>
      </Layout>
    )
  }

  if (!session) {
    return (
      <Layout>
        <Alert variant="error">Sesion no encontrada</Alert>
      </Layout>
    )
  }

  const config = webhook.config

  return (
    <Layout>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className={HEADER_CONTAINER}>
          <div className="flex items-center gap-4">
            <Button variant="ghost" onClick={() => navigate('/dashboard')}>
              <ArrowLeft className="w-4 h-4" />
            </Button>
            <div>
              <h1 className={HEADER_TITLE}>Webhooks</h1>
              <p className={HEADER_SUBTITLE}>
                {session.session.session_name} - Recibe eventos en tiempo real
              </p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <Button variant="ghost" onClick={() => webhook.refetch()} disabled={webhook.isActing}>
              <RefreshCw className={`w-4 h-4 ${webhook.isLoading ? 'animate-spin' : ''}`} />
            </Button>
            {!config && (
              <Button variant="primary" onClick={() => setShowCreateModal(true)}>
                <Plus className="w-4 h-4 mr-2" />
                Configurar Webhook
              </Button>
            )}
          </div>
        </div>

        {/* Connection Status Banner */}
        {config && (
          <ConnectionStatusBanner
            isListening={webhook.isListening}
            poolSession={webhook.poolSession}
            onStart={handleStartWebhook}
            onStop={handleStopWebhook}
            isStarting={webhook.isStarting}
            isStopping={webhook.isStopping}
          />
        )}

        {/* Webhook Config Card */}
        {config ? (
          <WebhookConfigCard
            config={config}
            isListening={webhook.isListening}
            isDeleting={webhook.isDeleting}
            showSecret={showSecret}
            onToggleSecret={() => setShowSecret(!showSecret)}
            onDelete={() => setShowDeleteConfirm(true)}
          />
        ) : (
          <EmptyWebhookCard onCreate={() => setShowCreateModal(true)} />
        )}

        {/* Pool Status */}
        {webhook.poolStatus && webhook.poolStatus.active_count > 0 && (
          <PoolStatusCard poolStatus={webhook.poolStatus} currentSessionId={sessionId} />
        )}

        {/* Events info */}
        <EventsInfoCard />
      </div>

      {/* Create Modal */}
      <Modal
        isOpen={showCreateModal}
        onClose={() => {
          setShowCreateModal(false)
          resetForm()
        }}
        title="Configurar Webhook"
        size="lg"
      >
        <div className="p-6 space-y-6">
          <Input
            label="URL del Webhook *"
            type="url"
            placeholder="https://tu-servidor.com/webhook"
            value={formData.url}
            onChange={(e) => setFormData({ ...formData, url: e.target.value })}
          />

          <Input
            label="Secret (opcional)"
            type="text"
            placeholder="Clave secreta para firmar requests"
            value={formData.secret}
            onChange={(e) => setFormData({ ...formData, secret: e.target.value })}
            helperText="Se usara para firmar los requests con HMAC-SHA256"
          />

          <div className="grid grid-cols-2 gap-4">
            <Input
              label="Timeout (ms)"
              type="number"
              value={formData.timeout_ms}
              onChange={(e) =>
                setFormData({ ...formData, timeout_ms: parseInt(e.target.value) || 5000 })
              }
              min={1000}
              max={30000}
            />
            <Input
              label="Max Reintentos"
              type="number"
              value={formData.max_retries}
              onChange={(e) =>
                setFormData({ ...formData, max_retries: parseInt(e.target.value) || 3 })
              }
              min={0}
              max={10}
            />
          </div>

          <div>
            <div className="flex items-center justify-between mb-3">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                Eventos a escuchar ({formData.events?.length || 0} seleccionados)
              </label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={selectAllEvents}
                  className="text-xs text-primary-600 hover:text-primary-700 dark:text-primary-400"
                >
                  Seleccionar todos
                </button>
                <span className="text-gray-300 dark:text-gray-600">|</span>
                <button
                  type="button"
                  onClick={clearAllEvents}
                  className="text-xs text-gray-500 hover:text-gray-700 dark:text-gray-400"
                >
                  Limpiar
                </button>
              </div>
            </div>
            <div className="grid gap-2 md:grid-cols-2 max-h-64 overflow-y-auto">
              {WEBHOOK_EVENTS.map((event) => (
                <label
                  key={event.id}
                  className={`${EVENT_ITEM_BASE} ${
                    formData.events?.includes(event.id)
                      ? EVENT_ITEM_SELECTED
                      : EVENT_ITEM_UNSELECTED
                  }`}
                >
                  <input
                    type="checkbox"
                    checked={formData.events?.includes(event.id)}
                    onChange={() => toggleEvent(event.id)}
                    className="w-4 h-4 text-primary-600 rounded focus:ring-primary-500"
                  />
                  <div className="min-w-0">
                    <p className={EVENT_LABEL}>
                      {event.label}
                    </p>
                    <p className="text-xs text-gray-500 dark:text-gray-400 truncate">
                      {event.id}
                    </p>
                  </div>
                </label>
              ))}
            </div>
            {(!formData.events || formData.events.length === 0) && (
              <p className="text-xs text-amber-600 dark:text-amber-400 mt-2">
                Si no seleccionas eventos, se recibiran todos los tipos de eventos
              </p>
            )}
          </div>

          {/* Auto-start option */}
          <div className={AUTO_START_BOX}>
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={autoStart}
                onChange={(e) => setAutoStart(e.target.checked)}
                className="w-5 h-5 text-primary-600 rounded focus:ring-primary-500"
              />
              <div>
                <p className="font-medium text-gray-900 dark:text-white">
                  Iniciar automaticamente
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  El webhook comenzara a escuchar eventos inmediatamente despues de crearse
                </p>
              </div>
            </label>
          </div>

          <div className={BUTTON_GROUP}>
            <Button
              variant="secondary"
              onClick={() => {
                setShowCreateModal(false)
                resetForm()
              }}
              fullWidth
            >
              Cancelar
            </Button>
            <Button
              variant="primary"
              onClick={handleCreateWebhook}
              isLoading={webhook.isCreating || webhook.isStarting}
              fullWidth
            >
              <Webhook className="w-4 h-4 mr-2" />
              {autoStart ? 'Crear e Iniciar' : 'Crear Webhook'}
            </Button>
          </div>
        </div>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal
        isOpen={showDeleteConfirm}
        onClose={() => setShowDeleteConfirm(false)}
        title="Eliminar Webhook"
        size="sm"
      >
        <div className="p-6">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-red-100 dark:bg-red-900/30 rounded-full">
              <Trash2 className="w-6 h-6 text-red-600 dark:text-red-400" />
            </div>
            <div>
              <p className="font-medium text-gray-900 dark:text-white">
                Estas seguro de eliminar el webhook?
              </p>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Se dejara de escuchar eventos y se eliminara la configuration
              </p>
            </div>
          </div>

          <div className="flex gap-3">
            <Button variant="secondary" onClick={() => setShowDeleteConfirm(false)} fullWidth>
              Cancelar
            </Button>
            <Button
              variant="danger"
              onClick={handleDeleteWebhook}
              isLoading={webhook.isDeleting}
              fullWidth
            >
              Eliminar
            </Button>
          </div>
        </div>
      </Modal>
    </Layout>
  )
}
